import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is the heat index?", a: "The heat index (also called 'apparent temperature' or 'feels like') is a measure of how hot it really feels when relative humidity is factored in with the air temperature. High humidity prevents sweat from evaporating efficiently, which is the body's primary cooling mechanism - making hot air feel even hotter." },
  { q: "At what heat index is it dangerous?", a: "NWS danger levels: 80-90 F means caution, 91-103 F means extreme caution, 103-124 F means danger, and 125 F or higher means extreme danger. Stay indoors, hydrate aggressively, and seek cool environments above 103 F." },
  { q: "Why does humidity make it feel hotter?", a: "Your body cools itself primarily by sweating - as sweat evaporates, it carries heat away from your skin. When humidity is high, the air is already saturated with moisture, so sweat evaporates much more slowly. This traps heat in your body and makes you feel significantly hotter than the thermometer indicates." },
  { q: "How is the heat index formula different from wind chill?", a: "Wind chill applies to cold weather - wind speeds evaporation and convective heat loss, making cold temperatures feel even colder. Heat index applies to hot weather - humidity slows evaporative cooling, making high temperatures feel hotter. Both are 'apparent temperature' measures representing how humans actually perceive temperature." },
  { q: "What is the Rothfusz regression equation?", a: "The National Weather Service uses the Rothfusz regression equation, developed by R.G. Rothfusz in 1990, to calculate heat index from temperature in F and relative humidity. It is accurate for temperatures above 80 F and humidity above 40%." },
  { q: "How do I protect myself from heat index dangers?", a: "Stay hydrated (drink water before you feel thirsty), wear light-colored loose clothing, seek shade or air conditioning, avoid outdoor activity during peak heat (10 AM-4 PM), never leave people or pets in parked cars, and watch for heat exhaustion symptoms: heavy sweating, weakness, cold/pale/clammy skin, weak pulse, nausea, and fainting." },
  { q: "Does the heat index apply in low humidity?", a: "The Rothfusz formula is most accurate above 80 F with relative humidity above 40%. In very dry conditions, the actual feels-like temperature may be lower than the measured temperature because sweating is very efficient." },
  { q: "What is the highest heat index ever recorded?", a: "One of the highest reported heat index values was approximately 178 F (81 C) in Dhahran, Saudi Arabia in 2003, with a temperature near 108 F and humidity near 68%. Heat index values above 130 F are life-threatening within minutes for unacclimatized people." },
];

const DANGER_SCALE = [
  ["< 80 F", "No risk", "Comfortable, normal activity OK"],
  ["80-90 F", "Caution", "Fatigue possible with prolonged exposure"],
  ["91-103 F", "Extreme Caution", "Heat cramps and exhaustion possible"],
  ["103-124 F", "Danger", "Heat cramps and exhaustion likely; heat stroke possible"],
  [">= 125 F", "Extreme Danger", "Heat stroke highly likely - seek shelter immediately"],
];

export default function HeatIndexCalculator() {
  const [tempF, setTempF] = useState(95);
  const [humidity, setHumidity] = useState(60);

  const T = tempF; const R = humidity;
  const hi = -42.379 + 2.04901523*T + 10.14333127*R
    - 0.22475541*T*R - 0.00683783*T*T - 0.05481717*R*R
    + 0.00122874*T*T*R + 0.00085282*T*R*R - 0.00000199*T*T*R*R;

  const danger = hi >= 125 ? { label: "Extreme Danger", color: "from-purple-700 to-purple-900" }
    : hi >= 103 ? { label: "Danger - Heat stroke possible", color: "from-red-600 to-red-800" }
    : hi >= 91 ? { label: "Extreme Caution", color: "from-orange-500 to-orange-700" }
    : hi >= 80 ? { label: "Caution", color: "from-yellow-500 to-yellow-700" }
    : { label: "Low Risk", color: "from-green-500 to-green-700" };

  const hiC = (hi - 32) * 5/9;
  const extraHeat = hi - tempF;

  const humidityRows = [20, 30, 40, 50, 60, 70, 80, 90];

  function calcHI(t: number, r: number) {
    return -42.379 + 2.04901523*t + 10.14333127*r
      - 0.22475541*t*r - 0.00683783*t*t - 0.05481717*r*r
      + 0.00122874*t*t*r + 0.00085282*t*r*r - 0.00000199*t*t*r*r;
  }

  return (
    <>
      <SEOHead
        title="Free Heat Index Calculator Online - Calculate How Hot It Really Feels Instantly | CalcHive"
        description="Free online heat index calculator. Calculate how hot it really feels by combining air temperature and relative humidity instantly. 100% free for everyone, no signup required."
        canonical="/heat-index-calculator"
        keywords="free heat index calculator, heat index calculator online free, feels like temperature calculator free, humidity heat calculator free, real feel heat calculator free"
        category="Weather Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-purple-600 dark:text-purple-400 bg-purple-50 dark:bg-purple-950/50 px-3 py-1 rounded-full mb-4 inline-block">Weather</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Heat Index Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free heat index calculator to estimate how hot it really feels from temperature and humidity. This heat index calculator online free also works as a feels like temperature calculator free, humidity heat calculator free, and real feel heat calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="temp" label="Air Temperature (F)" value={tempF} min={80} max={130} step={1} onChange={setTempF} format={v => `${v} F (${((v-32)*5/9).toFixed(1)} C)`} testId="input-temp" />
            <SliderInput id="humidity" label="Relative Humidity (%)" value={humidity} min={0} max={100} step={1} onChange={setHumidity} format={v => `${v}%`} testId="input-humidity" />
          </div>
          <motion.div key={`${tempF}-${humidity}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${danger.color} rounded-2xl p-6 mb-4 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Heat Index - Feels Like</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-heatindex">{hi.toFixed(1)} F</p>
              <p className="text-white/70 text-sm mt-1">{hiC.toFixed(1)} C - {danger.label}</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Actual Temp", value: `${tempF} F` },
                { label: "Extra Heat Felt", value: `+${extraHeat.toFixed(1)} F`, red: extraHeat > 10 },
                { label: "Danger Level", value: danger.label.split(" - ")[0] },
              ].map(({ label, value, red }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-sm font-extrabold ${red ? "text-red-600 dark:text-red-400" : "text-foreground"}`}>{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate the Heat Index for Free</h2>
          <p className="text-muted-foreground leading-relaxed">The National Weather Service uses the Rothfusz regression equation - a polynomial fit to Steadman's original 1979 human physiology model. It estimates apparent temperature by accounting for the reduced effectiveness of sweating when humidity is high. Valid for temperatures above 80 F and humidity above 40%.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-xs text-foreground space-y-1">
            <p>HI = -42.379 + 2.049T + 10.143R - 0.225TR - 0.00684T^2 - 0.0548R^2</p>
            <p>     + 0.00123T^2R + 0.000853TR^2 - 0.00000199T^2R^2</p>
            <p className="text-muted-foreground mt-2">T = temperature (F) - R = relative humidity (%)</p>
            <p className="text-muted-foreground">Valid for T at least 80 F and RH at least 40%</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Temperature and Humidity Combine to Create Real Feel Heat</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Relative Humidity", "Heat Index (F)", "Heat Index (C)", "Danger Level"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {humidityRows.map(rh => {
                  const h = calcHI(tempF, rh);
                  const hC = (h - 32) * 5/9;
                  const d = h >= 125 ? "Extreme Danger" : h >= 103 ? "Danger" : h >= 91 ? "Extreme Caution" : h >= 80 ? "Caution" : "Low Risk";
                  return (
                    <tr key={rh} className={`hover:bg-muted/30 ${rh === humidity ? "bg-purple-50 dark:bg-purple-950/20 font-semibold" : ""}`}>
                      <td className="py-2.5 px-4 font-semibold text-foreground">{rh}%{rh === humidity ? " (current)" : ""}</td>
                      <td className="py-2.5 px-4 text-purple-600 dark:text-purple-400 font-bold">{h.toFixed(1)} F</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{hC.toFixed(1)} C</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{d}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Feels Like Temperature Calculator for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Heat Index Range", "Danger Category", "Health Risks"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {DANGER_SCALE.map(([range, category, risks]) => (
                  <tr key={range} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-mono font-semibold text-foreground">{range}</td>
                    <td className="py-2.5 px-4 text-purple-600 dark:text-purple-400 font-bold">{category}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{risks}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/heat-index-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


